  ('islands-d0d1b9a2-moex-00030', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-ddeb88e9', 'sub-islands-d0d1b9a2-02', NULL, 'single_choice', '依預算法明文規定，下列事項應於中央政府相關預算書中以列表方式說明者為何？①因擔保、保', '["未來承諾之授權", "各機關單位補助地方政府 之經費", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "c868bde2a41c", "answer_pdf_sha1": "9585cbcdc6c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00031', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-ddeb88e9', 'sub-islands-d0d1b9a2-02', NULL, 'single_choice', '依預算法規定，下列須由行政院主計總處核定者，計有幾項？①各機關分配預算  ②預算籌編原', '["各機關概算編送期限與份數", "預算書表格式  ⑤轉入下年度之保留數準備  ⑥各機關 動支第一預備金", "2項", "3項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "c868bde2a41c", "answer_pdf_sha1": "9585cbcdc6c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00032', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-ddeb88e9', 'sub-islands-d0d1b9a2-02', NULL, 'single_choice', '甲機關某年度預算案之一般行政計畫項下共編列2,050萬元，包括有物品400萬元、其他補助及 捐助250萬元、委辦費1,200萬元、教育訓練費200萬元，其中委辦費被立法機關指定刪減600 萬元，其餘則照數通過，於年度執行中因受訓學員及受補助單位增加，導致教育訓練費及獎補助 經費各不敷200萬元及80萬元，而物品執行有剩餘160萬元，若將獎補助不敷經費優先以經費 流用方式予以滿足，依預算法相關規定，可支應不敷教育訓練費的數額應為？', '["50萬元", "80萬元", "110萬元", "160萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "c868bde2a41c", "answer_pdf_sha1": "9585cbcdc6c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00033', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-ddeb88e9', 'sub-islands-d0d1b9a2-02', NULL, 'single_choice', '我國預算法引進複式預算制度之作業觀念與精神，將政府預算劃分為經常預算與資本預算，試依 預算法對於經常門、資本門規定，下列敘述何者錯誤？', '["政府經常收支，應保持平衡，非因預算年度有異常情形，資本收入、公債與賒借收入及以前年 度歲計賸餘不得充經常支出之用", "經常收支如有賸餘，得移充資本支出之財源", "作業基金賸餘繳庫為資本收入", "政府釋股收入之股本面值及超過面值之股票買賣差價均編列為資本收入"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "c868bde2a41c", "answer_pdf_sha1": "9585cbcdc6c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00034', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-ddeb88e9', 'sub-islands-d0d1b9a2-02', NULL, 'single_choice', '政府預算的定義與功能可知，一個政府在一定期間內之收支計畫均必須透過預算的安排以作為執 行的準據，為昭公信，政府於一定期間內財政收支計畫的籌編、審議、執行及考核等事項予以法 制化，依我國預算法規定之預算籌編原則，下列敘述何者錯誤？', '["政府徵收賦稅、規費及因實施管制所發生之收入，或其他有強制性之收入，應先經預算法所定 預算程序", "政府不得於預算所定外，動用公款、處分公有財物或為投資之行為", "政府大宗動產、不動產之買賣或交換，均須依據預算法所定預算程序為之", "政府非依法律，不得於其預算外增加債務；其因調節短期國庫收支而發行債券時，依公共債務 法規定辦理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "c868bde2a41c", "answer_pdf_sha1": "9585cbcdc6c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00035', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-ddeb88e9', 'sub-islands-d0d1b9a2-02', NULL, 'single_choice', '依會計法規定，下列已歸檔之會計檔案自總決算公布或令行之日起至少應保存10年以上者，計', '["分會計之機器處理會計資料之貯存體暨處理手冊", "單位會計之帳簿", "附屬單位 會計之重要備查簿", "單位會計之會計憑證  ⑤總會計之會計報告"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "c868bde2a41c", "answer_pdf_sha1": "9585cbcdc6c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00036', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-ddeb88e9', 'sub-islands-d0d1b9a2-02', NULL, 'single_choice', '總會計年度報告之公告，應依下列何者規定辦理？', '["預算法", "會計法", "審計法", "決算法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "c868bde2a41c", "answer_pdf_sha1": "9585cbcdc6c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
